import sailpoint.object.*;
import sailpoint.tools.*;
import java.util.*;

log.info("===== Create AD Group =====");

requestId = UUID.randomUUID().toString();
log.info("RequestID: " + requestId);
log.info("GroupName: " + groupName);
log.info("ApplicationName: " + applicationName);

try {
  // Get the AD application
  Application app = context.getObjectByName(Application.class, applicationName);

  if (app == null) {
    log.error("Application not found: " + applicationName);
    isSuccess = false;
    errorMessage = "Application not found";
    return;
  }

  log.info("Application found");

  // Create provisioning plan
  ProvisioningPlan plan = new ProvisioningPlan();
  log.info("Plan created");

  // Create account request
  ProvisioningPlan.AccountRequest acctReq = new ProvisioningPlan.AccountRequest();
  acctReq.setApplication(applicationName);
  log.info("AccountRequest created");

  // Add attributes
  ProvisioningPlan.AttributeRequest attr1 = new ProvisioningPlan.AttributeRequest();
  attr1.setName("sAMAccountName");
  attr1.setValue(groupName);
  attr1.setOperation(ProvisioningPlan.Operation.Set);
  acctReq.add(attr1);

  ProvisioningPlan.AttributeRequest attr2 = new ProvisioningPlan.AttributeRequest();
  attr2.setName("cn");
  attr2.setValue(groupName);
  attr2.setOperation(ProvisioningPlan.Operation.Set);
  acctReq.add(attr2);

  ProvisioningPlan.AttributeRequest attr3 = new ProvisioningPlan.AttributeRequest();
  attr3.setName("displayName");
  attr3.setValue(groupName);
  attr3.setOperation(ProvisioningPlan.Operation.Set);
  acctReq.add(attr3);

  ProvisioningPlan.AttributeRequest attr4 = new ProvisioningPlan.AttributeRequest();
  attr4.setName("description");
  attr4.setValue(groupDescription);
  attr4.setOperation(ProvisioningPlan.Operation.Set);
  acctReq.add(attr4);

  ProvisioningPlan.AttributeRequest attr5 = new ProvisioningPlan.AttributeRequest();
  attr5.setName("groupType");
  attr5.setValue(groupType);
  attr5.setOperation(ProvisioningPlan.Operation.Set);
  acctReq.add(attr5);

  ProvisioningPlan.AttributeRequest attr6 = new ProvisioningPlan.AttributeRequest();
  attr6.setName("groupScope");
  attr6.setValue(groupScope);
  attr6.setOperation(ProvisioningPlan.Operation.Set);
  acctReq.add(attr6);

  ProvisioningPlan.AttributeRequest attr7 = new ProvisioningPlan.AttributeRequest();
  attr7.setName("ou");
  attr7.setValue(organizationalUnit);
  attr7.setOperation(ProvisioningPlan.Operation.Set);
  acctReq.add(attr7);

  ProvisioningPlan.AttributeRequest attr8 = new ProvisioningPlan.AttributeRequest();
  attr8.setName("managedBy");
  attr8.setValue(groupOwner);
  attr8.setOperation(ProvisioningPlan.Operation.Set);
  acctReq.add(attr8);

  if (groupEmail != null && groupEmail.length() > 0) {
    ProvisioningPlan.AttributeRequest attrEmail = new ProvisioningPlan.AttributeRequest();
    attrEmail.setName("mail");
    attrEmail.setValue(groupEmail);
    attrEmail.setOperation(ProvisioningPlan.Operation.Set);
    acctReq.add(attrEmail);
  }

  if (additionalAttributes != null && additionalAttributes.size() > 0) {
    for (Object key : additionalAttributes.keySet()) {
      String attrName = (String) key;
      Object attrValue = additionalAttributes.get(attrName);

      ProvisioningPlan.AttributeRequest attrCustom = new ProvisioningPlan.AttributeRequest();
      attrCustom.setName(attrName);
      attrCustom.setValue(attrValue);
      attrCustom.setOperation(ProvisioningPlan.Operation.Set);
      acctReq.add(attrCustom);
    }
  }

  plan.add(acctReq);

  log.info("Attributes added to plan");
  log.info("Executing provisioning...");

  // In IIQ 8.4, just call provision directly on the application
  // The application handles the connector internally
  Object result = app.provision(context, plan);

  log.info("Provisioning executed");
  log.info("Result: " + (result != null ? result.toString() : "null"));

  isSuccess = true;
  errorMessage = null;
  log.info("SUCCESS: Group created!");

} catch (Exception e) {
  log.error("Exception: " + e.getClass().getName());
  log.error("Message: " + e.getMessage());
  isSuccess = false;
  errorMessage = e.getMessage();

  if (e.getStackTrace() != null && e.getStackTrace().length > 0) {
    log.error("At: " + e.getStackTrace()[0].toString());
  }
}

log.info("Result: isSuccess=" + isSuccess + ", error=" + errorMessage);
